25	Surface::Surface(int width, int height, ColorSpace colorSpace, void *base)
26	    : fWidth(width),
27	      fHeight(height)
28	{
29	    fColorSpace = colorSpace;
30	    switch (colorSpace)
31	    {
32	        case RGBA8888:
33	        case FLOAT:
34	            fBytesPerPixel = 4;
35	            break;
36	
37	        case GRAY8:
38	            fBytesPerPixel = 1;
39	            break;
40	
41	        default:
42	            assert(0);
43	    }
44	
45	    fStride = width * fBytesPerPixel;
46	    if (base == nullptr)
47	    {
48	        fBaseAddress = reinterpret_cast<int>(memalign(kCacheLineSize,
49	             static_cast<size_t>(width * height * fBytesPerPixel)));
50	        fOwnedPointer = true;
51	    }
52	    else
53	    {
54	        fBaseAddress = reinterpret_cast<int>(base);
55	        fOwnedPointer = false;
56	    }
57	
58	    initializeOffsetVectors();
59	}
