67	void Surface::initializeOffsetVectors()
68	{
69	    // Screen space coordinate offset vector
70	    float twoOverWidth = 2.0 / fWidth;
71	    float twoOverHeight = 2.0 / fHeight;
72	    fXStep =
73	    {
74	        0, 1, 2, 3,
75	        0, 1, 2, 3,
76	        0, 1, 2, 3,
77	        0, 1, 2, 3,
78	    };
79	
80	    fXStep *= twoOverWidth;
81	
82	    fYStep =
83	    {
84	        0, 0, 0, 0,
85	        1, 1, 1, 1,
86	        2, 2, 2, 2,
87	        3, 3, 3, 3
88	    };
89	
90	    fYStep *= twoOverHeight;
91	
92	    f4x4AtOrigin =
93	    {
94	        0, 4, 8, 12,
95	        0, 4, 8, 12,
96	        0, 4, 8, 12,
97	        0, 4, 8, 12
98	    };
99	
100	    veci16_t widthOffset =
101	    {
102	        0, 0, 0, 0,
103	        4, 4, 4, 4,
104	        8, 8, 8, 8,
105	        12, 12, 12, 12
106	    };
107	
108	    f4x4AtOrigin += widthOffset * fWidth + fBaseAddress;
109	}
