111	void Surface::slowClearTile(int left, int top, unsigned int value)
112	{
113	    int width = min(kTileSize, fWidth - left);
114	    int height = min(kTileSize, fHeight - top);
115	
116	    switch (fColorSpace)
117	    {
118	        case RGBA8888:
119	        case FLOAT:
120	        {
121	            const int kStride = (fStride - (width * fBytesPerPixel)) / 4;
122	            uint32_t *ptr = reinterpret_cast<uint32_t*>(fBaseAddress + top * fStride
123	                + left * fBytesPerPixel);
124	            for (int y = 0; y < height; y++)
125	            {
126	                for (int x = 0; x < width; x++)
127	                    *ptr++ = value;
128	
129	                ptr += kStride;
130	            }
131	
132	            break;
133	        }
134	
135	        case GRAY8:
136	        {
137	            uint32_t *ptr = reinterpret_cast<uint32_t*>(fBaseAddress + (left + top * fWidth)
138	                * fBytesPerPixel);
139	            for (int y = 0; y < height; y++)
140	            {
141	                ::memset(ptr, static_cast<int>(value), static_cast<size_t>(width));
142	                ptr += fStride;
143	            }
144	
145	            break;
146	        }
147	    }
148	
149	
150	}
