152	// Push a NxN tile from the L2 cache back to system memory
153	// XXX hard coded for 32 bpp
154	void Surface::flushTile(int left, int top)
155	{
156	    int ptr = fBaseAddress + (left + top * fWidth) * fBytesPerPixel;
157	    int right = min(kTileSize, fWidth - left);
158	    int bottom = min(kTileSize, fHeight - top);
159	    const int kStride = (fWidth - right) * fBytesPerPixel;
160	    for (int y = 0; y < bottom; y++)
161	    {
162	        for (int x = 0; x < right; x += 16)
163	        {
164	            asm("dflush %0" : : "s" (ptr));
165	            ptr += kCacheLineSize;
166	        }
167	
168	        ptr += kStride;
169	    }
170	}
