30	// Convert a number in the range -1.0 <= n <= 1.0 to 0.0 <= n < 1.0
31	// If the number is less than 0, add 1 so it wraps around
32	inline vecf16_t wrapfv(vecf16_t in)
33	{
34	    return __builtin_nyuzi_vector_mixf(__builtin_nyuzi_mask_cmpf_lt(in, vecf16_t(0.0)),
35	                                       in + vecf16_t(1.0), in);
36	}
37	
38	// If a number is greater than max, make it be zero.
39	// This wraps in the case that 0 <= in <= max.
40	inline veci16_t wrapiv(veci16_t in, int max)
41	{
42	    return __builtin_nyuzi_vector_mixi(__builtin_nyuzi_mask_cmpf_lt(in, veci16_t(max)),
43	                                       in, veci16_t(0));
44	}
45	
46	} // namespace
