35	void RenderContext::setClearColor(float r, float g, float b)
36	{
37	    r = max(min(r, 1.0f), 0.0f);
38	    g = max(min(g, 1.0f), 0.0f);
39	    b = max(min(b, 1.0f), 0.0f);
40	
41	    fClearColor = 0xff000000 | (unsigned(b * 255.0) << 16) | (unsigned(g * 255.0) << 8)
42	                  | unsigned(r * 255.0);
43	}
