57	void RenderContext::bindTarget(RenderTarget *target)
58	{
59	    fRenderTarget = target;
60	    fFbWidth = fRenderTarget->getColorBuffer()->getWidth();
61	    fFbHeight = fRenderTarget->getColorBuffer()->getHeight();
62	    fTileColumns = (fFbWidth + kTileSize - 1) / kTileSize;
63	    fTileRows = (fFbHeight + kTileSize - 1) / kTileSize;
64	}
