93	void RenderContext::_wireframeTile(void *_castToContext, int index)
94	{
95	    static_cast<RenderContext*>(_castToContext)->wireframeTile(index);
96	}
97	
98	void RenderContext::finish()
99	{
100	    unsigned int kMaxTiles = static_cast<unsigned int>(fTileColumns * fTileRows);
101	    fTiles = new (fAllocator) TriangleArray[kMaxTiles];
102	    for (int i = 0; i < kMaxTiles; i++)
103	        fTiles[i].setAllocator(&fAllocator);
104	
105	    // Geometry phase.  Walk through each draw command and perform two steps
106	    // for each one:
107	    // 1. Call vertex shader on attributes (shadeVertices)
108	    // 2. Perform triangle setup and binning (setUpTriangle)
109	    fBaseSequenceNumber = 0;
110	    for (fRenderCommandIterator = fDrawQueue.begin(); fRenderCommandIterator != fDrawQueue.end();
111	            ++fRenderCommandIterator)
112	    {
113	        RenderState &state = *fRenderCommandIterator;
114	        int numVertices = state.fVertexAttrBuffer->getNumElements();
115	        int numTriangles = state.fIndexBuffer->getNumElements() / 3;
116	        state.fVertexParams = static_cast<float*>(fAllocator.alloc(
117	                                  static_cast<unsigned int>(numVertices)
118	                                  * static_cast<unsigned int>(state.fShader->getNumParams())
119	                                  * sizeof(int)));
120	        parallel_execute(_shadeVertices, this, (numVertices + 15) / 16);
121	        parallel_execute(_setUpTriangle, this, numTriangles);
122	        fBaseSequenceNumber += numTriangles;
123	    }
124	
125	    // Pixel phase.  Shade the pixels and write back.
126	    if (fWireframeMode)
127	        parallel_execute(_wireframeTile, this, fTileColumns * fTileRows);
128	    else
129	        parallel_execute(_fillTile, this, fTileColumns * fTileRows);
130	
131	#if DISPLAY_STATS
132	    printf("total triangles = %d\n", fBaseSequenceNumber);
133	    printf("used %zu bytes\n", fAllocator.bytesUsed());
134	#endif
135	
136	    // Clean up memory
137	    // First reset draw queue to clean up, then allocator, which frees
138	    // memory it is using.
139	    fDrawQueue.reset();
140	    fAllocator.reset();
141	    fCurrentState.fUniforms = nullptr;	// Remove dangling pointer
142	    fClearColorBuffer = false;
143	}
144	
145	//
146	// Compute vertex parameters.  This shades all vertices in the attribute array,
147	// even if they are not referenced by the index array.
148	//
149	void RenderContext::shadeVertices(int index)
150	{
151	    const RenderState &state = *fRenderCommandIterator;
152	    int numVertices = state.fVertexAttrBuffer->getNumElements() - index * 16;
153	    vmask_t mask;
154	    if (numVertices < 16)
155	        mask = (1 << numVertices) - 1;
156	    else
157	        mask = 0xffff;
158	
159	    int attribsPerVertex = state.fShader->getNumAttribs();
160	    vecf16_t packedAttribs[attribsPerVertex];
161	    int startIndex = index * 16;
162	    for (int attrib = 0; attrib < attribsPerVertex; attrib++)
163	    {
164	        packedAttribs[attrib] = vecf16_t(state.fVertexAttrBuffer->gatherElements(startIndex,
165	                                         attrib, mask));
166	    }
167	
168	    int paramsPerVertex = state.fShader->getNumParams();
169	    vecf16_t packedParams[paramsPerVertex];
170	    state.fShader->shadeVertices(packedParams, packedAttribs, state.fUniforms, mask);
171	
172	    const veci16_t kStepVector = { 0, 4, 8, 12, 16, 20, 24, 28, 32, 36, 40, 44, 48, 52, 56, 60 };
173	    const veci16_t paramStepVector = kStepVector * paramsPerVertex;
174	    float *outBuf = state.fVertexParams + paramsPerVertex * index * 16;
175	    veci16_t paramPtr = paramStepVector + reinterpret_cast<int>(outBuf);
176	    for (int param = 0; param < paramsPerVertex; param++)
177	    {
178	        __builtin_nyuzi_scatter_storef_masked(paramPtr, packedParams[param], mask);
179	        paramPtr += 4;
180	    }
181	}
