183	namespace
184	{
185	
186	const float kNearWClip = 1.0;
187	
188	void interpolate(float *outParams, const float *inParams0, const float *inParams1, int numParams,
189	                 float distance)
190	{
191	    for (int i = 0; i < numParams; i++)
192	        outParams[i] = inParams0[i] * (1.0 - distance) + inParams1[i] * distance;
193	}
194	
195	} // namespace
196	
197	//
198	// Clip a triangle where one vertex is past the near clip plane.
199	// The clipped vertex is always params0.  This creates two new triangles above
200	// the clip plane.
201	//
202	//    1 +-------+ 2
203	//      | \    /
204	//      |   \ /
205	//  np1 +----+ np2
206	//      |.../
207	//      |../    clipped
208	//      |./
209	//      |/
210	//      0
211	//
212	
213	void RenderContext::clipOne(int sequence, const RenderState &state, const float *params0,
214	                            const float *params1, const float *params2)
215	{
216	    float newPoint1[kMaxParams];
217	    float newPoint2[kMaxParams];
218	
219	    interpolate(newPoint1, params1, params0, state.fParamsPerVertex, (params1[kParamW] - kNearWClip)
220	                / (params1[kParamW] - params0[kParamW]));
221	    interpolate(newPoint2, params2, params0, state.fParamsPerVertex, (params2[kParamW] - kNearWClip)
222	                / (params2[kParamW] - params0[kParamW]));
223	    enqueueTriangle(sequence, state, newPoint1, params1, newPoint2);
224	    enqueueTriangle(sequence, state, newPoint2, params1, params2);
225	}
226	
227	//
228	// Clip a triangle where two vertices are past the near clip plane.
229	// The clipped vertices are always param0 and params1. Adjust the
230	// bottom two points of the triangle.
231	//
232	//                 2
233	//                 +
234	//               / |
235	//              /  |
236	//             /   |
237	//        np1 +----+ np2
238	//           /.....|
239	//          /......|  clipped
240	//         /.......|
241	//        +--------+
242	//        1        0
243	//
244	
245	void RenderContext::clipTwo(int sequence, const RenderState &state, const float *params0,
246	                            const float *params1, const float *params2)
247	{
248	    float newPoint1[kMaxParams];
249	    float newPoint2[kMaxParams];
250	
251	    interpolate(newPoint1, params2, params1, state.fParamsPerVertex, (params2[kParamW] - kNearWClip)
252	                / (params2[kParamW] - params1[kParamW]));
253	    interpolate(newPoint2, params2, params0, state.fParamsPerVertex, (params2[kParamW] - kNearWClip)
254	                / (params2[kParamW] - params0[kParamW]));
255	    enqueueTriangle(sequence, state, newPoint2, newPoint1, params2);
256	}
257	
258	void RenderContext::setUpTriangle(int triangleIndex)
259	{
260	    RenderState &state = *fRenderCommandIterator;
261	    int vertexIndex = triangleIndex * 3;
262	    const int *indices = static_cast<const int*>(state.fIndexBuffer->getData());
263	    int offset0 = indices[vertexIndex] * state.fParamsPerVertex;
264	    int offset1 = indices[vertexIndex + 1] * state.fParamsPerVertex;
265	    int offset2 = indices[vertexIndex + 2] * state.fParamsPerVertex;
266	    const float *params0 = &state.fVertexParams[offset0];
267	    const float *params1 = &state.fVertexParams[offset1];
268	    const float *params2 = &state.fVertexParams[offset2];
269	
270	    // Determine which point (if any) are clipped against the near plane, call
271	    // appropriate clip routine with triangle rotated appropriately. We don't
272	    // clip against other planes.
273	    // XXX This is not quite correct; it needs to perform homogenous clipping.  Also,
274	    // the viewing volume is zNear = -1, zFar = -inf
275	    int clipMask = (params0[kParamW] < kNearWClip ? 1 : 0) | (params1[kParamW] < kNearWClip ? 2 : 0)
276	                   | (params2[kParamW] < kNearWClip ? 4 : 0);
277	    switch (clipMask)
278	    {
279	    case 0:
280	        // Not clipped at all.
281	        enqueueTriangle(fBaseSequenceNumber + triangleIndex, state,
282	                        params0, params1, params2);
283	        break;
284	
285	    case 1:
286	        clipOne(fBaseSequenceNumber + triangleIndex, state, params0, params1, params2);
287	        break;
288	
289	    case 2:
290	        clipOne(fBaseSequenceNumber + triangleIndex, state, params1, params2, params0);
291	        break;
292	
293	    case 4:
294	        clipOne(fBaseSequenceNumber + triangleIndex, state, params2, params0, params1);
295	        break;
296	
297	    case 3:
298	        clipTwo(fBaseSequenceNumber + triangleIndex, state, params0, params1, params2);
299	        break;
300	
301	    case 6:
302	        clipTwo(fBaseSequenceNumber + triangleIndex, state, params1, params2, params0);
303	        break;
304	
305	    case 5:
306	        clipTwo(fBaseSequenceNumber + triangleIndex, state, params2, params0, params1);
307	        break;
308	
309	        // Else is totally clipped, ignore
310	    }
311	}
312	
313	//
314	// Performs the second half of triangle setup after clipping: perspective
315	// division, backface culling, and binning.
316	//
317	
318	void RenderContext::enqueueTriangle(int sequence, const RenderState &state, const float *params0,
319	                                    const float *params1, const float *params2)
320	{
321	    Triangle tri;
322	    tri.sequenceNumber = sequence;
323	    tri.state = &state;
324	
325	    // Perform perspective division.
326	    // XXX Z should be divided against W here.  This is a bit of a hack.
327	    float oneOverW0 = 1.0 / params0[kParamW];
328	    float oneOverW1 = 1.0 / params1[kParamW];
329	    float oneOverW2 = 1.0 / params2[kParamW];
330	    tri.x0 = params0[kParamX] * oneOverW0;
331	    tri.y0 = params0[kParamY] * oneOverW0;
332	    tri.z0 = params0[kParamZ];
333	    tri.x1 = params1[kParamX] * oneOverW1;
334	    tri.y1 = params1[kParamY] * oneOverW1;
335	    tri.z1 = params1[kParamZ];
336	    tri.x2 = params2[kParamX] * oneOverW2;
337	    tri.y2 = params2[kParamY] * oneOverW2;
338	    tri.z2 = params2[kParamZ];
339	
340	    // Convert screen space coordinates to raster coordinates
341	    int halfWidth = fFbWidth / 2;
342	    int halfHeight = fFbHeight / 2;
343	    tri.x0Rast = tri.x0 * halfWidth + halfWidth;
344	    tri.y0Rast = -tri.y0 * halfHeight + halfHeight;
345	    tri.x1Rast = tri.x1 * halfWidth + halfWidth;
346	    tri.y1Rast = -tri.y1 * halfHeight + halfHeight;
347	    tri.x2Rast = tri.x2 * halfWidth + halfWidth;
348	    tri.y2Rast = -tri.y2 * halfHeight + halfHeight;
349	
350	    int winding = (tri.x1Rast - tri.x0Rast) * (tri.y2Rast - tri.y0Rast) - (tri.y1Rast - tri.y0Rast)
351	                  * (tri.x2Rast - tri.x0Rast);
352	    if (winding == 0)
353	        return;	// remove edge-on triangles, which won't be rasterized correctly.
354	
355	    tri.woundCCW = winding < 0;
356	
357	    // Backface culling
358	    if ((state.cullingMode == RenderState::kCullCW && !tri.woundCCW)
359	            || (state.cullingMode == RenderState::kCullCCW && tri.woundCCW))
360	        return;
361	
362	    // Compute bounding box
363	    int bbLeft = tri.x0Rast < tri.x1Rast ? tri.x0Rast : tri.x1Rast;
364	    bbLeft = tri.x2Rast < bbLeft ? tri.x2Rast : bbLeft;
365	    int bbTop = tri.y0Rast < tri.y1Rast ? tri.y0Rast : tri.y1Rast;
366	    bbTop = tri.y2Rast < bbTop ? tri.y2Rast : bbTop;
367	    int bbRight = tri.x0Rast > tri.x1Rast ? tri.x0Rast : tri.x1Rast;
368	    bbRight = tri.x2Rast > bbRight ? tri.x2Rast : bbRight;
369	    int bbBottom = tri.y0Rast > tri.y1Rast ? tri.y0Rast : tri.y1Rast;
370	    bbBottom = tri.y2Rast > bbBottom ? tri.y2Rast : bbBottom;
371	
372	    // Cull triangles that are outside the sides of the view frustum
373	    if (bbRight < 0 || bbLeft >= fFbWidth || bbBottom < 0 || bbTop >= fFbHeight)
374	        return;
375	
376	    // Copy parameters into triangle structure, skipping position which is already
377	    // in x0/y0/z0/x1...
378	    unsigned int paramSize = sizeof(float) * static_cast<unsigned int>(state.fParamsPerVertex - 4);
379	    float *params = static_cast<float*>(fAllocator.alloc(paramSize * 3));
380	    memcpy(params, params0 + 4, paramSize);
381	    memcpy(params + state.fParamsPerVertex - 4, params1 + 4, paramSize);
382	    memcpy(params + (state.fParamsPerVertex - 4) * 2, params2 + 4, paramSize);
383	    tri.params = params;
384	
385	    // Determine which tiles this triangle may overlap with a simple
386	    // bounding box check.  Enqueue it in the queues for each tile.
387	    int minTileX = max(bbLeft / kTileSize, 0);
388	    int maxTileX = min(bbRight / kTileSize, fTileColumns - 1);
389	    int minTileY = max(bbTop / kTileSize, 0);
390	    int maxTileY = min(bbBottom / kTileSize, fTileRows - 1);
391	    for (int tiley = minTileY; tiley <= maxTileY; tiley++)
392	    {
393	        for (int tilex = minTileX; tilex <= maxTileX; tilex++)
394	            fTiles[tiley * fTileColumns + tilex].append(tri);
395	    }
396	}
397	
398	namespace
399	{
400	
401	// These assume counterclockwise winding
402	bool edgeRejected(int left, int top, int right, int bottom,
403	                  int x1, int y1, int x2, int y2)
404	{
405	    // Find a reject corner
406	    int cx = y2 > y1 ? right : left;
407	    int cy = x2 > x1 ? top : bottom;
408	
409	    return (x2 - x1) * (cy - y1) - (y2 - y1) * (cx - x1) > 0;
410	}
411	
412	bool triangleRejected(int left, int top, int right, int bottom,
413	                      int x1, int y1, int x2, int y2, int x3, int y3)
414	{
415	    return edgeRejected(left, top, right, bottom, x1, y1, x2, y2)
416	           || edgeRejected(left, top, right, bottom, x2, y2, x3, y3)
417	           || edgeRejected(left, top, right, bottom, x3, y3, x1, y1);
418	}
419	
420	} // namespace
421	
422	void RenderContext::fillTile(int index)
423	{
424	    const int x = index % fTileColumns;
425	    const int y = index / fTileColumns;
426	    const int tileX = x * kTileSize;
427	    const int tileY = y * kTileSize;
428	    TriangleArray &tile = fTiles[y * fTileColumns + x];
429	    Surface *colorBuffer = fRenderTarget->getColorBuffer();
430	
431	    if (fClearColorBuffer)
432	        colorBuffer->clearTile(tileX, tileY, fClearColor);
433	
434	    // Initialize Z-Buffer to -infinity
435	    if (fRenderTarget->getDepthBuffer())
436	        fRenderTarget->getDepthBuffer()->clearTile(tileX, tileY, 0xff800000);
437	
438	    // The triangles may have been reordered during the parallel vertex shading
439	    // phase.  Put them back in the order they were submitted.
440	    tile.sort();
441	
442	    // Walk through all triangles that overlap this tile and render
443	    TriangleFiller filler(fRenderTarget);
444	    for (const Triangle &tri : tile)
445	    {
446	        const RenderState &state = *tri.state;
447	
448	        // Do a better check to see if this triangle overlaps the tile.
449	        // If not, skip setting up interpolators.
450	        if (tri.woundCCW)
451	        {
452	            if (triangleRejected(tileX, tileY, tileX + kTileSize,
453	                                 tileY + kTileSize, tri.x0Rast, tri.y0Rast, tri.x1Rast,
454	                                 tri.y1Rast, tri.x2Rast, tri.y2Rast))
455	            {
456	                continue;
457	            }
458	        }
459	        else
460	        {
461	            if (triangleRejected(tileX, tileY, tileX + kTileSize,
462	                                 tileY + kTileSize, tri.x0Rast, tri.y0Rast, tri.x2Rast,
463	                                 tri.y2Rast, tri.x1Rast, tri.y1Rast))
464	            {
465	                continue;
466	            }
467	        }
468	
469	        // Set up parameters and rasterize triangle.
470	        filler.setUpTriangle(&state, tri.x0, tri.y0, tri.z0, tri.x1, tri.y1, tri.z1, tri.x2,
471	                             tri.y2, tri.z2);
472	        for (int paramI = 0; paramI < state.fParamsPerVertex; paramI++)
473	        {
474	            filler.setUpParam(tri.params[paramI],
475	                              tri.params[(state.fParamsPerVertex - 4) + paramI],
476	                              tri.params[(state.fParamsPerVertex - 4) * 2 + paramI]);
477	        }
478	
479	        if (tri.woundCCW)
480	        {
481	            fillTriangle(filler, tileX, tileY,
482	                         tri.x0Rast, tri.y0Rast, tri.x1Rast, tri.y1Rast, tri.x2Rast, tri.y2Rast,
483	                         fFbWidth, fFbHeight);
484	        }
485	        else
486	        {
487	            fillTriangle(filler, tileX, tileY,
488	                         tri.x0Rast, tri.y0Rast, tri.x2Rast, tri.y2Rast, tri.x1Rast, tri.y1Rast,
489	                         fFbWidth, fFbHeight);
490	        }
491	    }
492	
493	    colorBuffer->flushTile(tileX, tileY);
494	}
495	
496	//
497	// Fill a tile, except with wireframe only
498	//
499	
500	void RenderContext::wireframeTile(int index)
501	{
502	    const int x = index % fTileColumns;
503	    const int y = index / fTileColumns;
504	    const int tileX = x * kTileSize;
505	    const int tileY = y * kTileSize;
506	    const TriangleArray &tile = fTiles[y * fTileColumns + x];
507	
508	    Surface *colorBuffer = fRenderTarget->getColorBuffer();
509	    colorBuffer->clearTile(tileX, tileY, fClearColor);
510	    int bottomClip = tileY + kTileSize - 1;
511	    int rightClip = tileX + kTileSize - 1;
512	    if (bottomClip >= colorBuffer->getHeight())
513	        bottomClip = colorBuffer->getHeight() - 1;
514	
515	    if (rightClip >= colorBuffer->getWidth())
516	        rightClip = colorBuffer->getWidth() - 1;
517	
518	    for (const Triangle &tri : tile)
519	    {
520	        drawLineClipped(colorBuffer, tri.x0Rast, tri.y0Rast, tri.x1Rast, tri.y1Rast, 0xffffffff,
521	                        tileX, tileY, rightClip, bottomClip);
522	        drawLineClipped(colorBuffer, tri.x1Rast, tri.y1Rast, tri.x2Rast, tri.y2Rast, 0xffffffff,
523	                        tileX, tileY, rightClip, bottomClip);
524	        drawLineClipped(colorBuffer, tri.x2Rast, tri.y2Rast, tri.x0Rast, tri.y0Rast, 0xffffffff,
525	                        tileX, tileY, rightClip, bottomClip);
526	    }
527	
528	    colorBuffer->flushTile(tileX, tileY);
529	}
