26	namespace librender
27	{
28	
29	const int kCacheLineSize = 64;
30	const int kTileSize = 64;
31	const int kVectorSize = 64;
32	
33	static_assert(__builtin_clz(kTileSize) & 1, "Tile size must be power of four");
34	
35	//
36	// Surface is a chunk of 2D bitmap memory.
37	// Because this contains vector elements, this structure must be aligned to vector width.
38	// If this is to be used as a destination, the width and height must be a multiple of
39	// 64 bytes.
40	//
41	
42	class Surface
43	{
44	public:
45	    enum ColorSpace
46	    {
47	        RGBA8888,
48	        FLOAT,
49	        GRAY8
50	    };
51	
52	    // If base is not null, this will use it as surface memory and will
53	    // not attempt to free it. Otherwise this will allocate its own
54	    // memory to use.
55	    Surface(int width, int height, ColorSpace, void *base = nullptr);
56	
57	    ~Surface();
58	
59	    Surface(const Surface&) = delete;
60	    Surface& operator=(const Surface&) = delete;
61	
62	    // Write values to a 4x4 block, with lanes arranged as follows:
63	    //   0  1  2  3
64	    //   4  5  6  7
65	    //   8  9 10 11
66	    //  12 13 14 15
67	    // XXX hardcoded for RGBA8888 color space
68	    void writeBlockMasked(int left, int top, vmask_t mask, vecu16_t values)
69	    {
70	        veci16_t ptrs = f4x4AtOrigin + left * 4 + top * fStride;
71	        __builtin_nyuzi_scatter_storei_masked(ptrs, values, mask);
72	    }
73	
74	    // Read values from a 4x4 block, in same order as writeBlockMasked
75	    // XXX hardcoded for RGBA8888 color space
76	    vecu16_t readBlock(int left, int top) const
77	    {
78	        veci16_t ptrs = f4x4AtOrigin + left * 4 + top * fStride;
79	        return __builtin_nyuzi_gather_loadi(ptrs);
80	    }
81	
82	    // Set all 32-bit values in a tile to a predefined value.
83	    void clearTile(int left, int top, unsigned int value)
84	    {
85	        if (kTileSize == 64 && fWidth - left >= 64 && fHeight - top >=
86	            64 && (fColorSpace == RGBA8888 || fColorSpace == FLOAT))
87	        {
88	            // Fast clear using block stores
89	            vecu16_t vval = value;
90	            vecu16_t *ptr = reinterpret_cast<vecu16_t*>(fBaseAddress + (left + top * fWidth)
91	                * fBytesPerPixel);
92	            const int kStride = fStride / kCacheLineSize;
93	            for (int y = 0; y < 64; y++)
94	            {
95	                ptr[0] = vval;
96	                ptr[1] = vval;
97	                ptr[2] = vval;
98	                ptr[3] = vval;
99	                ptr += kStride;
100	            }
101	        }
102	        else
103	            slowClearTile(left, top, value);
104	    }
105	
106	    // Push a tile from the L2 cache back to system memory
107	    void flushTile(int left, int top);
108	
109	    void readPixels(veci16_t tx, veci16_t ty, vmask_t mask, vecf16_t *outColor) const
110	    {
111	        veci16_t pointers = (ty * fStride + tx * fBytesPerPixel)
112	                            + fBaseAddress;
113	        veci16_t packedColor = __builtin_nyuzi_gather_loadi_masked(pointers & ~3, mask);
114	        const float kOneOver255 = 1.0 / 255.0;
115	        switch (fColorSpace)
116	        {
117	            case RGBA8888:
118	                outColor[0] = __builtin_convertvector(packedColor & 255, vecf16_t)
119	                                    * kOneOver255;
120	                outColor[1] = __builtin_convertvector((packedColor >> 8) & 255,
121	                                    vecf16_t) * kOneOver255;
122	                outColor[2] = __builtin_convertvector((packedColor >> 16) & 255,
123	                                    vecf16_t) * kOneOver255;
124	                outColor[3] = __builtin_convertvector((packedColor >> 24) & 255,
125	                                    vecf16_t) * kOneOver255;
126	                break;
127	
128	            case GRAY8:
129	                packedColor = (packedColor >> ((pointers & 3) * 8)) & 0xff;
130	                outColor[0] = __builtin_convertvector(packedColor, vecf16_t)
131	                    * kOneOver255;
132	                outColor[1] = outColor[2] = outColor[3];
133	                break;
134	
135	            case FLOAT:
136	                outColor[0] = reinterpret_cast<vecf16_t>(packedColor);
137	                outColor[1] = outColor[2] = outColor[3];
138	                break;
139	        }
140	    }
141	
142	    inline int getWidth() const
143	    {
144	        return fWidth;
145	    }
146	
147	    inline int getHeight() const
148	    {
149	        return fHeight;
150	    }
151	
152	    inline int getStride() const
153	    {
154	        return fStride;
155	    }
156	
157	    void *bits() const
158	    {
159	        return reinterpret_cast<void*>(fBaseAddress);
160	    }
161	
162	    void *operator new(size_t size)
163	    {
164	        // Because this structure has vector members, it must be vector width aligned
165	        return memalign(sizeof(vecu16_t), size);
166	    }
167	
168	    vecf16_t getXStep() const
169	    {
170	        return fXStep;
171	    }
172	
173	    vecf16_t getYStep() const
174	    {
175	        return fYStep;
176	    }
177	
178	    ColorSpace getColorSpace() const
179	    {
180	        return fColorSpace;
181	    }
182	
183	private:
184	    void initializeOffsetVectors();
185	    void slowClearTile(int left, int top, unsigned int value);
186	
187	    veci16_t f4x4AtOrigin;
188	
189	    // For each pixel in a 4x4 grid, these represent the distance in
190	    // screen coordinates (-1.0 to 1.0) from the upper left pixel.
191	    vecf16_t fXStep;
192	    vecf16_t fYStep;
193	
194	    int fWidth;
195	    int fHeight;
196	    int fStride;
197	    int fBaseAddress;
198	    bool fOwnedPointer;
199	    ColorSpace fColorSpace;
200	    int fBytesPerPixel;
201	};
