//
class RenderTarget
{
public:
    void setColorBuffer(Surface *buffer)
    {
        fColorBuffer = buffer;
    }

    void setDepthBuffer(Surface *buffer)
    {
        fDepthBuffer = buffer;
    }

    Surface *getColorBuffer() const
    {
        return fColorBuffer;
    }

    Surface *getDepthBuffer() const
    {
        return fDepthBuffer;
    }

private:
    Surface *fColorBuffer = nullptr;
    Surface *fDepthBuffer = nullptr;
};

