17	//
18	// Render a torus with shadows computed on the fly. Demonstrates using
19	// render-to-texture with librender.
20	//
21	
22	#include <math.h>
23	#include <Matrix.h>
24	#include <nyuzi.h>
25	#include <RenderContext.h>
