33	
34	// Debug option to see scene from perspective of light
35	//#define SHOW_SHADOW_MAP 1
36	
37	using namespace librender;
38	
39	namespace
40	{
41	const int kLightmapSize = 256;
42	const float kGroundVertices[] =
43	{
44	    -1.0, -1.0, -1.0,
45	     1.0, -1.0, -1.0,
46	     1.0,  1.0, -1.0,
47	    -1.0,  1.0, -1.0
48	};
49	const int kNumGroundVertices = 4;
50	const int kGroundIndices[] = { 0, 1, 2, 2, 3, 0 };
51	const int kNumGroundIndices = 6;
52	} // namespace
53	
54	// All threads start execution here.
55	int main()
56	{
57	    void *frameBuffer;
58	    if (get_current_thread_id() != 0)
59	        worker_thread();
60	
61	    frameBuffer = init_vga(VGA_MODE_640x480);
62	
63	    start_all_threads();
64	
65	    RenderContext *context = new RenderContext();
66	
67	    // Shadow map that is both a source texture and render target
68	    // XXX Ideally we would make this texture 16 bits with a single channel,
69	    // but librender currently hardcodes one surface format (RGBA8888),
70	    // which wastes some memory and limits the depth resolution to 256.
71	    // It would also be ideal to bind the texture as the depth buffer so
72	    // we didn't need a color buffer.
73	    Surface *lightMapSurface = new Surface(kLightmapSize, kLightmapSize, Surface::FLOAT);
74	    Surface *lightDepthBuffer = new Surface(kLightmapSize, kLightmapSize, Surface::FLOAT);
75	    RenderTarget *lightMapTarget = new RenderTarget();
76	    lightMapTarget->setColorBuffer(lightMapSurface);
77	    lightMapTarget->setDepthBuffer(lightDepthBuffer);
78	    Shader *lightMapShader = new ShadowMapShader();
79	    Texture *lightMapTexture = new Texture();
80	    lightMapTexture->enableBilinearFiltering(true);
81	    lightMapTexture->setMipSurface(0, lightMapSurface);
82	
83	    // Output framebuffer target
84	    RenderTarget *outputTarget = new RenderTarget();
85	    Surface *colorBuffer = new Surface(FB_WIDTH, FB_HEIGHT, Surface::RGBA8888, frameBuffer);
86	    Surface *depthBuffer = new Surface(FB_WIDTH, FB_HEIGHT, Surface::FLOAT);
87	    outputTarget->setColorBuffer(colorBuffer);
88	    outputTarget->setDepthBuffer(depthBuffer);
89	#if !SHOW_SHADOW_MAP
90	    Shader *outputShader = new OutputShader();
91	#endif
92	
93	    ShadowMapUniforms lightMapUniforms;
94	    OutputUniforms outputUniforms;
95	
96	    const RenderBuffer torusVertexBuffer(kTorusVertices, kNumTorusVertices,
97	        6 * sizeof(float));
98	    const RenderBuffer torusIndexBuffer(kTorusIndices, kNumTorusIndices,
99	        sizeof(int));
100	    const RenderBuffer groundVertexBuffer(kGroundVertices, kNumGroundVertices,
101	        3 * sizeof(float));
102	    const RenderBuffer groundIndexBuffer(kGroundIndices, kNumGroundIndices,
103	        sizeof(int));
104	
105	    Matrix modelMatrix;
106	#if !SHOW_SHADOW_MAP
107	    Matrix projectionMatrix = Matrix::getProjectionMatrix(FB_WIDTH, FB_HEIGHT);
108	#endif
109	    Matrix viewMatrix = Matrix::lookAt(Vec3(-1.2, 1.4, 0.1), Vec3(0, 0, 0), Vec3(0, 0, 1));
110	
111	    outputUniforms.fDirectional = 0.6f;
112	    outputUniforms.fAmbient = 0.2f;
113	    Matrix modelRotationMatrix = Matrix::getRotationMatrix(M_PI / 16, Vec3(0, 1, 0));
114	    Matrix viewRotationMatrix = Matrix::getRotationMatrix(M_PI / 20, Vec3(0, 0, 1));
115	    Matrix lightViewMatrix = Matrix::lookAt(Vec3(0, 0, 2),
116	        Vec3(0, 0, 0), Vec3(0, 1, 0));
117	    outputUniforms.fLightVector = lightViewMatrix.upper3x3() * Vec3(0, 0, -1);
118	    context->enableDepthBuffer(true);
119	
