131	        lightMapUniforms.fMVPMatrix = lightViewMatrix;
132	        context->bindUniforms(&lightMapUniforms, sizeof(lightMapUniforms));
133	        context->bindVertexAttrs(&groundVertexBuffer);
134	        context->drawElements(&groundIndexBuffer);
135	
136	        lightMapUniforms.fMVPMatrix = lightViewMatrix * modelMatrix;
137	        context->bindUniforms(&lightMapUniforms, sizeof(lightMapUniforms));
138	        context->bindVertexAttrs(&torusVertexBuffer);
139	        context->drawElements(&torusIndexBuffer);
